<script setup lang="ts">
import { onMounted, ref, watch } from 'vue';

const botStore = useBotStore();
const container = ref<HTMLElement>();
const currentPair = ref('BTCUSDT');

// Map freqtrade pair format (BTC/USDT) to TV format (BTCUSDT)
function toTVSymbol(pair: string) {
  return 'OKX:' + pair.replace('/', '');
}

function loadWidget() {
  if (!container.value) return;
  container.value.innerHTML = '';
  new (window as any).TradingView.widget({
    autosize: true,
    symbol: toTVSymbol(currentPair.value),
    interval: '15',
    timezone: 'Etc/UTC',
    theme: document.documentElement.classList.contains('dark') ? 'dark' : 'light',
    style: '1',
    locale: 'en',
    toolbar_bg: '#f1f3f6',
    enable_publishing: false,
    allow_symbol_change: true,
    container_id: 'tv-chart-container',
    studies: ['MASimple@tv-basicstudies', 'RSI@tv-basicstudies', 'Volume@tv-basicstudies'],
  });
}

onMounted(() => {
  // Load TradingView widget script
  const script = document.createElement('script');
  script.src = 'https://s3.tradingview.com/tv.js';
  script.onload = loadWidget;
  document.head.appendChild(script);
});

// Watch for pair changes from bot
watch(() => botStore.activeBot?.selectedPair, (newPair) => {
  if (newPair) {
    currentPair.value = newPair;
    loadWidget();
  }
});
</script>

<template>
  <div class="h-full w-full flex flex-col">
    <div class="flex items-center gap-3 p-2 border-b border-surface-200">
      <span class="font-bold text-lg">TradingView</span>
      <select v-model="currentPair" @change="loadWidget" class="p-inputtext text-sm">
        <option v-for="pair in (botStore.activeBot?.whitelist || ['BTC/USDT','ETH/USDT','SOL/USDT','BNB/USDT'])" :key="pair" :value="pair">{{ pair }}</option>
      </select>
    </div>
    <div id="tv-chart-container" ref="container" class="flex-1" style="min-height: 500px"></div>
  </div>
</template>
